import{_ as a,o as e,c as t,a2 as i}from"./chunks/framework.CGYl2SZ_.js";const o=JSON.parse('{"title":"usage tracking","description":"usage tracking 页面","frontmatter":{"title":"usage tracking","description":"usage tracking 页面"},"headers":[],"relativePath":"concepts/usage-tracking.md","filePath":"concepts/usage-tracking.md"}');const l=a({name:"concepts/usage-tracking.md"},[["render",function(a,o,l,n,r,s){return e(),t("div",null,[...o[0]||(o[0]=[i('<h1 id="使用量跟踪" tabindex="-1">使用量跟踪 <a class="header-anchor" href="#使用量跟踪" aria-label="Permalink to &quot;使用量跟踪&quot;">​</a></h1><h1 id="使用量跟踪-1" tabindex="-1">使用量跟踪 <a class="header-anchor" href="#使用量跟踪-1" aria-label="Permalink to &quot;使用量跟踪&quot;">​</a></h1><h2 id="是什么" tabindex="-1">是什么 <a class="header-anchor" href="#是什么" aria-label="Permalink to &quot;是什么&quot;">​</a></h2><ul><li>直接从提供商的用量/配额端点拉取。</li><li>无估计成本；仅提供商报告的窗口。</li></ul><h2 id="显示位置" tabindex="-1">显示位置 <a class="header-anchor" href="#显示位置" aria-label="Permalink to &quot;显示位置&quot;">​</a></h2><ul><li>聊天中的 <code>/status</code>：带有会话令牌 + 估计成本（仅 API 密钥）的 emoji 丰富状态卡。当前模型提供商的提供商用量（如果有）。</li><li>聊天中的 <code>/usage off|tokens|full</code>：每回复用量页脚（OAuth 仅显示令牌）。</li><li>聊天中的 <code>/usage cost</code>：从 OpenClaw 会话日志聚合的本地成本摘要。</li><li>CLI：<code>openclaw status --usage</code> 打印完整的每个提供商细分。</li><li>CLI：<code>openclaw channels list</code> 在提供商配置旁边打印相同的用量快照（使用 <code>--no-usage</code> 跳过）。</li><li>macOS 菜单栏：上下文下的&quot;用量&quot;部分（仅在可用时显示）。</li></ul><h2 id="提供商-凭据" tabindex="-1">提供商 + 凭据 <a class="header-anchor" href="#提供商-凭据" aria-label="Permalink to &quot;提供商 + 凭据&quot;">​</a></h2><ul><li><strong>Anthropic (Claude)</strong>：认证配置中的 OAuth 令牌。</li><li><strong>GitHub Copilot</strong>：认证配置中的 OAuth 令牌。</li><li><strong>Gemini CLI</strong>：认证配置中的 OAuth 令牌。</li><li><strong>Antigravity</strong>：认证配置中的 OAuth 令牌。</li><li><strong>OpenAI Codex</strong>：认证配置中的 OAuth 令牌（存在时使用 accountId）。</li><li><strong>MiniMax</strong>：API 密钥（编码计划密钥；<code>MINIMAX_CODE_PLAN_KEY</code> 或 <code>MINIMAX_API_KEY</code>）；使用 5 小时编码计划窗口。</li><li><strong>z.ai</strong>：通过 env/config/认证存储的 API 密钥。</li></ul><p>如果没有匹配的 OAuth/API 凭据，用量被隐藏。</p>',9)])])}]]);export{o as __pageData,l as default};
